SELECT *
FROM error_logs
WHERE instance_id = (SELECT MAX(instance_id) FROM instances);

SELECT instance_id, instance_type, environment, location
FROM instances
WHERE instance_id IN (SELECT instance_id FROM workloads);

SELECT el.instance_id, COUNT(*) AS total_errors
FROM error_logs el
GROUP BY el.instance_id;

SELECT instances.instance_id
FROM instances
JOIN capacity_planning ON instances.instance_id = capacity_planning.instance_id;

SELECT instance_id, SUM(memory_size) AS total_memory_required
FROM resource_requirements
GROUP BY instance_id;

SELECT instances.*, resource_requirements.cpu_cores, resource_requirements.memory_size, resource_requirements.disk_space
FROM instances
INNER JOIN resource_requirements ON instances.instance_id = resource_requirements.instance_id;

SELECT instance_id, mem_max
FROM instances
WHERE mem_max = (SELECT MAX(mem_max) FROM instances);
